// app/qui-sommes-nous/page.jsx
import { prisma } from "@/lib/prisma";
import Link from "next/link";
import { ArrowLeft, Target, Heart, ShieldCheck } from "lucide-react";

export const dynamic = "force-dynamic";

const C = { yellow: "#FFC801", saffron: "#FF9932", teal: "#114C5A", arctic: "#F1F6F4", white: "#ffffff" };

export default async function QuiSommesNous() {
  const animateurs = await prisma.animateur.findMany({
    orderBy: { createdAt: 'asc' }
  });

  return (
    <div style={{ fontFamily: "'Montserrat',sans-serif", background: C.arctic, color: C.teal, minHeight: "100vh" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800;900&display=swap');
        *{box-sizing:border-box;}
      `}</style>

      {/* Header simple */}
      <div style={{ background: C.white, padding: "24px 32px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <Link href="/" style={{ display: "flex", alignItems: "center", gap: "8px", textDecoration: "none", color: C.teal, fontWeight: 700, fontSize: "14px" }}>
            <ArrowLeft size={16} /> Retour à l'accueil
          </Link>
          <h1 style={{ fontSize: "16px", fontWeight: 900, textTransform: "uppercase", letterSpacing: "2px" }}>Make Your Moment</h1>
        </div>
      </div>

      <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "64px 32px" }}>
        
        {/* Intro */}
        <div style={{ textAlign: "center", maxWidth: "800px", margin: "0 auto 80px" }}>
          <h2 style={{ fontSize: "clamp(2rem, 4vw, 3rem)", fontWeight: 900, letterSpacing: "-1px", marginBottom: "24px" }}>
            Créer des souvenirs, <br/><span style={{ color: C.saffron }}>c'est notre métier.</span>
          </h2>
          <p style={{ fontSize: "16px", color: "#5a7a84", lineHeight: 1.8, fontWeight: 500 }}>
            Make Your Moment est une association née de la passion de professionnels de l'éducation. Notre mission est d'offrir des séjours de qualité, sécurisés, où chaque participant s'épanouit et grandit au contact des autres.
          </p>
        </div>

        {/* L'équipe */}
        <div style={{ marginBottom: "40px", display: "flex", alignItems: "center", gap: "16px" }}>
          <h3 style={{ fontSize: "24px", fontWeight: 900 }}>Notre Équipe d'Encadrants</h3>
          <div style={{ height: "2px", flex: 1, background: "#e2e8f0" }} />
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: "32px" }}>
          {animateurs.map(anim => (
            <div key={anim.id} style={{ background: C.white, borderRadius: "24px", overflow: "hidden", boxShadow: "0 10px 30px rgba(17,76,90,0.05)", transition: "transform .3s" }} onMouseEnter={e => e.currentTarget.style.transform = "translateY(-6px)"} onMouseLeave={e => e.currentTarget.style.transform = "translateY(0)"}>
              <div style={{ height: "240px", background: C.arctic }}>
                {anim.imageUrl ? (
                  <img src={anim.imageUrl} alt={anim.nom} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                ) : (
                  <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", color: "#ccc" }}>Pas de photo</div>
                )}
              </div>
              <div style={{ padding: "24px" }}>
                <p style={{ fontSize: "11px", fontWeight: 800, color: C.saffron, textTransform: "uppercase", letterSpacing: "1px", marginBottom: "6px" }}>{anim.role}</p>
                <h4 style={{ fontSize: "20px", fontWeight: 900, color: C.teal, marginBottom: "12px" }}>{anim.nom}</h4>
                <p style={{ fontSize: "13px", color: "#5a7a84", lineHeight: 1.6, fontWeight: 500 }}>{anim.bio}</p>
              </div>
            </div>
          ))}
          
          {animateurs.length === 0 && (
             <p style={{ gridColumn: "1/-1", textAlign: "center", color: "#8aaa" }}>L'équipe est en cours de constitution...</p>
          )}
        </div>

      </div>
    </div>
  );
}